selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.6 </span>Joint Control<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The joint control interfaces provide precise control over each robot joint, supporting multiple control modes and joint groups.</strong></p>", "a[href=\"#id3\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Control Modes<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id8\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Safety Notes<a class=\"headerlink\" href=\"#id8\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"../../example/Cpp.html#cpp-joint-control\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Robot Joint Control Example<a class=\"headerlink\" href=\"#cpp-joint-control\" title=\"Link to this heading\">\uf0c1</a></h3><p>This example demonstrates how to control the robot\u2019s joints using ROS2 and the Ruckig library. It includes the following features:</p>", "a[href=\"../../example/Python.html#py-joint-control\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Robot joint control example<a class=\"headerlink\" href=\"#py-joint-control\" title=\"Link to this heading\">\uf0c1</a></h3><p>This example shows how to use ROS2 and the Ruckig library to control robot joints. The example implements the following features:</p>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Joint State Query Service<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id4\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Supported Joints<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#id5\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Joint Control Topics<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h2><p>Joints are controlled by body part (arms, legs, waist, head), and closed-loop control can be implemented using status feedback.</p>", "a[href=\"#tbl-joint-order\"]": "<table class=\"docutils align-default\" id=\"tbl-joint-order\">\n<thead>\n<tr class=\"row-odd\"><th class=\"head\"><p>Joint group</p></th>\n<th class=\"head\"><p>Length</p></th>\n<th class=\"head\"><p>Contents</p></th>\n<th class=\"head\"><p>Notes</p></th>\n</tr>\n</thead>\n<tbody>\n<tr class=\"row-even\"><td><p>head</p></td>\n<td><p>2</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">head_yaw</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">head_pitch</span></code></p></td>\n<td><p>only yaw now, and pitch is unavailable</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>waist</p></td>\n<td><p>3</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">wrist_yaw</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">wrist_pitch</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">wrist_roll</span></code></p></td>\n<td><p></p></td>\n</tr>\n<tr class=\"row-even\"><td><p>arm</p></td>\n<td><p>7*2</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">shoulder_pitch</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">shoulder_roll</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">shoulder_yaw</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">elbow</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">wrist_yaw</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">wrist_pitch</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">wrist_roll</span></code></p></td>\n<td><p>All left-side joints first, then all right-side joints</p></td>\n</tr>\n<tr class=\"row-odd\"><td><p>leg</p></td>\n<td><p>6*2</p></td>\n<td><p><code class=\"docutils literal notranslate\"><span class=\"pre\">hip_pitch</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">hip_roll</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">hip_yaw</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">knee</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">ankle_pitch</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">ankle_roll</span></code></p></td>\n<td><p>All left-side joints first, then all right-side joints</p></td>\n</tr>\n</tbody>\n</table>", "a[href=\"#rosmsg-jointstate\"]": "<ul id=\"rosmsg-jointstate\">\n<li><p><code class=\"docutils literal notranslate\"><span class=\"pre\">JointState</span></code> ros2-msg @ hal/msg/JointState.msg</p>\n<div class=\"highlight-perl notranslate\"><div class=\"highlight\"><pre><span></span><span class=\"c1\"># Joint state information</span>\n<span class=\"n\">string</span><span class=\"w\"> </span><span class=\"n\">name</span><span class=\"w\">                      </span><span class=\"c1\"># Joint name (currently unused)</span>\n<span class=\"n\">float64</span><span class=\"w\"> </span><span class=\"n\">position</span><span class=\"w\">                 </span><span class=\"c1\"># Position (rad)</span>\n<span class=\"n\">float64</span><span class=\"w\"> </span><span class=\"n\">velocity</span><span class=\"w\">                 </span><span class=\"c1\"># Velocity (rad/s)</span>\n<span class=\"n\">float64</span><span class=\"w\"> </span><span class=\"n\">effort</span><span class=\"w\">                   </span><span class=\"c1\"># Torque (N\u00b7m)</span>\n<span class=\"n\">uint8</span><span class=\"w\"> </span><span class=\"n\">coil_temp</span><span class=\"w\">                  </span><span class=\"c1\"># Coil temperature (\u00b0C)</span>\n<span class=\"n\">uint8</span><span class=\"w\"> </span><span class=\"n\">motor_temp</span><span class=\"w\">                 </span><span class=\"c1\"># Motor temperature (\u00b0C)</span>\n<span class=\"n\">uint8</span><span class=\"w\"> </span><span class=\"n\">motor_vol</span><span class=\"w\">                  </span><span class=\"c1\"># Motor voltage (V)</span>\n</pre></div>\n</div>\n</li>\n</ul>", "a[href=\"#id7\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Programming Examples<a class=\"headerlink\" href=\"#id7\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed examples and code explanations, refer to:</p>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Key Features<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><h3>Control Modes<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h3>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
